import { defineStore } from 'pinia'
import { ref, computed } from 'vue'

export interface CartItem {
  id: string
  name: string
  price: number
  quantity: number
  image: string
}

export const useCartStore = defineStore('cart', () => {
  const items = ref<CartItem[]>([])
  const couponCode = ref<string>('')
  const isLoading = ref(false)

  const itemCount = computed(() =>
    items.value.reduce((sum, item) => sum + item.quantity, 0)
  )

  const subtotal = computed(() =>
    items.value.reduce((sum, item) => sum + item.price * item.quantity, 0)
  )

  const discount = computed(() => {
    if (couponCode.value === 'SAVE10') return subtotal.value * 0.1
    if (couponCode.value === 'SAVE20') return subtotal.value * 0.2
    return 0
  })

  const total = computed(() => Math.max(0, subtotal.value - discount.value))

  function addItem(product: Omit<CartItem, 'quantity'>) {
    const existing = items.value.find(i => i.id === product.id)
    if (existing) {
      existing.quantity++
    } else {
      items.value.push({ ...product, quantity: 1 })
    }
  }

  function removeItem(id: string) {
    items.value = items.value.filter(i => i.id !== id)
  }

  function updateQuantity(id: string, quantity: number) {
    const item = items.value.find(i => i.id === id)
    if (item) item.quantity = Math.max(1, quantity)
  }

  function applyCoupon(code: string) {
    couponCode.value = code.toUpperCase()
  }

  function clearCart() {
    items.value = []
    couponCode.value = ''
  }

  return {
    items, itemCount, subtotal, discount, total, isLoading,
    addItem, removeItem, updateQuantity, applyCoupon, clearCart
  }
})

import { createRouter, createWebHistory, RouteRecordRaw } from 'vue-router'
import { useAuthStore } from '@/stores/auth'

const routes: RouteRecordRaw[] = [
  {
    path: '/login',
    name: 'Login',
    component: () => import('@/views/Login.vue'),
    meta: { requiresAuth: false }
  },
  {
    path: '/',
    component: () => import('@/layouts/MainLayout.vue'),
    children: [
      { path: 'dashboard', name: 'Dashboard', component: () => import('@/views/Dashboard.vue'), meta: { requiresAuth: true } },
      { path: 'profile', name: 'Profile', component: () => import('@/views/Profile.vue'), meta: { requiresAuth: true, roles: ['user', 'admin'] } },
      { path: 'admin', name: 'Admin', component: () => import('@/views/Admin.vue'), meta: { requiresAuth: true, roles: ['admin'] } }
    ]
  }
]

const router = createRouter({
  history: createWebHistory(),
  routes
})

router.beforeEach(async (to, from, next) => {
  const authStore = useAuthStore()
  const requiresAuth = to.matched.some(record => record.meta.requiresAuth)

  if (requiresAuth && !authStore.isAuthenticated) {
    next({ name: 'Login', query: { redirect: to.fullPath } })
    return
  }

  if (!requiresAuth && authStore.isAuthenticated && to.name === 'Login') {
    next({ name: 'Dashboard' })
    return
  }

  if (to.meta.roles && !authStore.hasRole(to.meta.roles as string[])) {
    next({ name: 'Forbidden' })
    return
  }

  next()
})

export default router

export default defineNuxtRouteMiddleware(async (to) => {
  const token = useCookie('auth-token')
  const user = useState('user', () => null)

  if (!token.value && to.meta.requiresAuth) {
    return navigateTo('/login')
  }

  if (token.value && !user.value) {
    try {
      const { data } = await useFetch('/api/auth/me', {
        headers: { Authorization: `Bearer ${token.value}` }
      })
      if (data.value) {
        user.value = data.value
      } else {
        token.value = null
        return navigateTo('/login')
      }
    } catch (error) {
      token.value = null
      return navigateTo('/login')
    }
  }
})

